import { localInputToISOWithOffset, utcToLocalInputValue } from '@linm-soft-org/linm-web-common-components';
import type { VoucherFormSnapshot } from '../../../../../components/voucher';
import type { UpdateAdvancePaymentDto } from '../../../../../services/kt/models';
import { ktService } from '../../../../../services/kt/ktService';
import { emptyTamUngLine, type TamUngLineModel } from '../types/tamUngLine.types';

export type TamUngSnapshot = {
  voucherDate: string;
  createdDate: string;
  customerId: string;
  customerCode: string;
  customerName: string;
  customerPhone: string;
  creditAccountCode: string;
  creditAccountName: string;
  description: string;
  processingLevel: string;
  lines: TamUngLineModel[];
};

export const todayLocalDateInput = () => new Date().toISOString().slice(0, 10);

export const tamUngToVoucherSnapshot = (snap: TamUngSnapshot): VoucherFormSnapshot => ({
  voucherDate: snap.voucherDate,
  receiptKind: '',
  customerId: snap.customerId,
  customerCode: snap.customerCode,
  customerName: snap.customerName,
  representativeName: '',
  customerPhone: snap.customerPhone,
  reference: '',
  referenceCustomerName: '',
  accountCode: snap.creditAccountCode,
  accountName: snap.creditAccountName,
  counterAccountCode: '',
  counterAccountName: '',
  description: snap.description,
  processingLevel: snap.processingLevel,
  lines: snap.lines.map(l => ({
    accountCode: l.accountCode,
    accountName: l.accountName,
    debitAmount: l.amount,
    description: l.description,
    costCenterCode: l.costCenterCode,
  })),
});

export const mapDtoToTamUngSnapshot = (
  dto: Awaited<ReturnType<typeof ktService.getAdvancePayment>>,
): TamUngSnapshot => ({
  voucherDate: utcToLocalInputValue(dto.voucherDate).slice(0, 10),
  createdDate: dto.createdDate ? utcToLocalInputValue(dto.createdDate).slice(0, 10) : '',
  customerId: dto.customerId ?? '',
  customerCode: dto.customerCode ?? '',
  customerName: dto.customerName ?? '',
  customerPhone: dto.customerPhone ?? '',
  creditAccountCode: dto.creditAccountCode ?? '',
  creditAccountName: dto.creditAccountName ?? '',
  description: dto.description ?? '',
  processingLevel: dto.processingLevel ?? '',
  lines: dto.lines.length > 0
    ? dto.lines.map(line => ({
      accountCode: line.accountCode,
      accountName: line.counterAccountName ?? '',
      amount: line.amount,
      description: line.description ?? '',
      costCenterCode: line.costCenterCode ?? '',
    }))
    : [emptyTamUngLine()],
});

export function buildTamUngSavePayload(input: {
  voucherDate: string;
  createdDate: string;
  creditAccountCode: string;
  customerId: string;
  description: string;
  processingLevel: string;
  lines: TamUngLineModel[];
}): UpdateAdvancePaymentDto {
  const validLines = input.lines.filter(l => l.accountCode && l.amount > 0);
  return {
    voucherDate: localInputToISOWithOffset(input.voucherDate),
    createdDate: localInputToISOWithOffset(input.createdDate || todayLocalDateInput()),
    creditAccountCode: input.creditAccountCode.trim(),
    customerId: input.customerId || undefined,
    description: input.description.trim(),
    processingLevel: input.processingLevel,
    lines: validLines.map(l => ({
      accountCode: l.accountCode,
      amount: Number(l.amount),
      description: (l.description || input.description).trim(),
      costCenterCode: l.costCenterCode || undefined,
    })),
  };
}

export const snapshotFromFormFields = (fields: {
  voucherDate: string;
  createdDate: string;
  customerId: string;
  customerCode: string;
  customerName: string;
  customerPhone: string;
  creditAccountCode: string;
  creditAccountName: string;
  description: string;
  processingLevel: string;
  lines: TamUngLineModel[];
}): TamUngSnapshot => ({ ...fields });
