import { createField, newLineId, type IField } from '../../../../form-shared';
import type { TamUngLineModel } from '../types/tamUngLine.types';

export type TamUngLineFieldKey = keyof TamUngLineModel;

export interface TamUngLineFieldState {
  lineId: string;
  fields: Record<TamUngLineFieldKey, IField<string | number>>;
}

const LINE_DISPLAY_ONLY: TamUngLineFieldKey[] = ['accountName'];

export function initTamUngLineFields(model: TamUngLineModel, lineId: string): TamUngLineFieldState {
  const fields = {} as Record<TamUngLineFieldKey, IField<string | number>>;
  (Object.keys(model) as TamUngLineFieldKey[]).forEach(key => {
    fields[key] = createField(model[key], { displayOnly: LINE_DISPLAY_ONLY.includes(key) });
  });
  return { lineId, fields };
}

export function tamUngLineFromFields(line: TamUngLineFieldState): TamUngLineModel {
  const out = {} as TamUngLineModel;
  (Object.keys(line.fields) as TamUngLineFieldKey[]).forEach(key => {
    out[key] = line.fields[key].value as never;
  });
  return out;
}

export function tamUngLinesFromState(lines: TamUngLineFieldState[]): TamUngLineModel[] {
  return lines.map(tamUngLineFromFields);
}

export { newLineId };
