import React from 'react';
import { LabelMoney, Select } from '@linm-soft-org/linm-web-common-components';
import type { TamUngFormViewModel } from '../hooks/useTamUngFormController';

export const TamUngFooterSection: React.FC<{ vm: TamUngFormViewModel }> = ({ vm }) => {
  const {
    labels,
    tid,
    styles: df,
    viewSectionClass,
    processingLevel,
    setProcessingLevel,
    processingOpts,
    selectDisabled,
    fieldErrors,
    patchHeaderFieldError,
    totalAmount,
  } = vm;

  return (
    <div className={[df.footer, viewSectionClass].filter(Boolean).join(' ')}>
      <div id={tid('field-processingLevel')} className={df.footerLeft} data-testid={tid('field-processingLevel')}>
        <label className={df.label}>{labels.processingLevel}</label>
        <Select
          options={processingOpts}
          value={processingLevel}
          error={fieldErrors.processingLevel}
          onChange={e => {
            const v = e.target.value;
            setProcessingLevel(v);
            patchHeaderFieldError('processingLevel', v);
          }}
          disabled={selectDisabled}
          title={selectDisabled ? 'Chỉ xem — nhấn Sửa để đổi mức xử lý' : undefined}
        />
      </div>
      <div className={df.totalBlock}>
        <LabelMoney
          label={`${labels.totalLabel}:`}
          value={totalAmount}
          variant="footer"
          emphasize
          data-testid={tid('footer-totalAmount')}
        />
      </div>
    </div>
  );
};
